    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook: returns a debounced copy of `value` after `delay` ms,
// plus a flag indicating a debounce is currently pending.
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // If the value already matches, there's nothing to debounce.
        if (value === debouncedValue) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup: clears the pending timeout on every change AND on unmount,
        // preventing stale updates / memory leaks (Requirement 8).
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, [value, delay, debouncedValue]);

    return [debouncedValue, isPending];
