// Splits `text` into segments and wraps case-insensitive matches of `query`
// in <mark> tags. Uses indexOf (no regex) so special characters are safe
// (Requirement 9) and there's no ReDoS / syntax-error risk.
function highlightMatch(text, query) {
    if (!query) return text;

    const lowerText = text.toLowerCase();
    const lowerQuery = query.toLowerCase();
    const segments = [];
    let start = 0;
    let matchIndex = lowerText.indexOf(lowerQuery, start);
    let key = 0;

    while (matchIndex !== -1) {
        // Text before the match.
        if (matchIndex > start) {
            segments.push(text.slice(start, matchIndex));
        }
        // The matched portion, preserving original casing.
        segments.push(
            <mark key={key++}>{text.slice(matchIndex, matchIndex + query.length)}</mark>
        );
        start = matchIndex + query.length;
        matchIndex = lowerText.indexOf(lowerQuery, start);
    }

    // Remaining trailing text.
    if (start < text.length) {
        segments.push(text.slice(start));
    }

    return segments;
}

function ResourceList() {
    const [searchInput, setSearchInput] = useState('');
    const [debouncedSearch, isPending] = useDebouncedValue(searchInput, 300);

    // Whitespace-only input is treated as empty (Requirement 9).
